"""
MKT Original Commentary — Nehemiah chapters 9–10
Run: python3 scripts/zc-original-nehemiah-9-10.py

Ch9:  ṣôm wᵉśaqqîm wᵉʾādāmāh — tripartite mourning vocabulary (9:1)
      bāḏal — separation verb; the covenant-identity term recurs from Ezra (9:2)
      qārᵉʾû bᵉsēpher tôrat — Torah-reading liturgy; the public recitation form (9:3)
      mᵉḇôrāk šem kᵉḇôdᵉḵā — the Levitical blessing formula; the meḇôrāk vocable (9:5)
      ʾattāh hûʾ YHWH lᵉḇaddeḵā — solus Dominus; the monotheistic confession (9:6)
      bāḥartā bᵉʾaḇrām — the election of Abraham; bāḥar for covenant choice (9:7)
      rûaḥᵃkā haṭṭôḇāh — your good Spirit; first explicit positive-Spirit reference (9:20)
      ṣaddîq ʾattāh — the righteousness confession; the legal-covenant attribute (9:33)
Ch10: hattirshātāʾ — the Governor title; Aramaic-Persian administrative loanword (10:1)
      lōʾ naʿăzōḇ ʾet-bêt ʾĕlōhênû — the covenant climax; not-forsake the house (10:39)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "9": {
    "1": "<p><span class='term'>ṣôm wᵉśaqqîm wᵉʾādāmāh</span> — fasting, sackcloth, and earth/dust (9:1). The triad of penitential mourning — <span class='term'>ṣôm</span> (fasting; voluntary bodily deprivation), <span class='term'>śaq</span> (sackcloth; coarse goat-hair fabric against the skin), and <span class='term'>ʾādāmāh</span> (earth/dirt placed on the head) — constitutes the canonical mourning posture of the OT. The third element distinguishes this from ordinary fasting: heaping earth on the head signals identification with mortality and dust (Gen 3:19) as a bodily enactment of covenant unworthiness. The combination appears in prophetic penitential contexts (Joel 1:8-14; Isa 58:5) and connects the Nehemiah assembly to the established liturgical grammar of communal repentance.</p>",
    "2": "<p><span class='term'>wayyiḇḏᵉlû zeraʿ Yiśrāʾēl mikkol-bᵉnê nēḵār</span> — the seed of Israel separated themselves from all foreigners (9:2). The Nip'al of <span class='term'>bāḏal</span> (to divide, separate) returns from Ezra 9–10 where the same verb diagnosed the intermarriage crisis and mandated the solution. Here it governs the liturgical assembly that precedes the prayer: the community has enacted the separation before it confesses the failure to maintain it. <span class='term'>zeraʿ Yiśrāʾēl</span> (seed of Israel) is an unusual collective for the covenant people — the seed/offspring terminology that evokes the Abrahamic promise (<em>lᵉzarʿᵃkā ʾettēn</em>, Gen 15:18) — establishing the assembly's covenant identity before the confession begins.</p>",
    "3": "<p><span class='term'>wayyāqûmû ʿal-mᵉqômām wayyiqrᵉʾû bᵉsēpher tôrat YHWH</span> — they stood in their place and read from the book of the Torah of YHWH (9:3). The phrase <span class='term'>bᵉsēpher tôrat YHWH</span> is the standard designation for the written Torah as a defined documentary entity (cf. 8:1, 3, 8, 18). The temporal notation — a quarter of the day for reading and a quarter for confession — establishes a liturgical rhythm: Torah-reading creates the penitential awareness that the confession expresses. The liturgy moves from word to response, from hearing the covenant standard to acknowledging the covenant failure. The standing position (<em>wayyāqûmû ʿal-mᵉqômām</em>) is the posture of reverence before the word, established in the Ezra ceremony of ch 8.</p>",
    "4": "<p><span class='term'>wayyāqem ʿal-maʿălê halayyᵉwiyyim</span> — Levites stood on the staircase/platform (9:4). The <span class='term'>maʿălāh</span> (ascent, step, platform) is the liturgical elevation from which the Levites led the assembly — the same elevated position from which Ezra read the Torah (8:4: <em>migdāl ʿēṣ</em>, wooden platform). The function is both practical (amplification of voice) and theological (elevation signals the mediatory role: the Levites stand between the congregation and YHWH as the prayer-leaders). The list of Levitical names represents the official liturgical body of the restoration community.</p>",
    "5": "<p><span class='term'>qûmû bārᵉkû ʾet-YHWH ʾĕlōhêkem min-hāʿôlām ʿaḏ hāʿôlām</span> — stand, bless the LORD your God from everlasting to everlasting (9:5). The formulaic call to blessing uses <span class='term'>bāraḵ</span> in its liturgical sense of public ascription of worth to YHWH — the congregation performing the <em>beraḵāh</em> (blessing) as acknowledgment that all good flows from YHWH to Israel, not the reverse. The temporal frame <em>min-hāʿôlām ʿaḏ hāʿôlām</em> (from age to age) appears in Ps 106:48 and throughout the Psalter's doxological formulae — the Levites are invoking the psalmic blessing tradition. <span class='term'>mᵉḇōrāk šem kᵉḇôdᵉḵā</span> (blessed be your glorious name) — the <em>šem kāḇôd</em> compound designates the divine name as the locus of YHWH's manifest glory.</p>",
    "6": "<p><span class='term'>ʾattāh hûʾ YHWH lᵉḇaddeḵā</span> — you alone are the LORD (9:6). The prayer opens with a <em>solus Dominus</em> monotheism formula: YHWH is the sole Creator-Lord, not one deity among many. The pronoun-predicate construction <em>ʾattāh hûʾ</em> (you, he = you are he/the one) is emphatic identification — a formula of exclusive attribution also found in Isa 37:16 and Ps 102:28. The scope of the creation enumeration — heavens, highest heavens, their host, earth and all on it, seas and all in them — structurally echoes Gen 1 without quoting it. <span class='term'>mᵉḥayyeh ʾet-kullām</span> (you give life to all of them) adds the sustaining function to the originating one: creation is not a past act but an ongoing relationship.</p>",
    "7": "<p><span class='term'>ʾăšer bāḥartā bᵉʾaḇrām</span> — who chose Abram (9:7). The verb <span class='term'>bāḥar</span> (to choose, select, elect) is the standard election verb of Deuteronomy applied here to the Abrahamic election rather than the more common Mosaic-covenantal context. The prayer traces election to Abram before the covenant, establishing that the covenant rests on divine initiative rather than Israelite qualification. The name-change notice — <em>wayyāśem šᵉmô ʾAḇrāhām</em> — is syntactically attached to the election: the renaming and the covenant (Gen 17:5) are presented as a single elective act. <span class='term'>ḵî māṣāʾtā ʾet-libbô neʾĕmān lᵉpānêḵā</span> (for you found his heart faithful before you) — the <em>neʾĕmān</em> (faithful/reliable) attributed to Abraham inverts the typical covenant formula: YHWH is usually the <em>ʾēl neʾĕmān</em> (Deut 7:9); here Abraham's faithfulness is acknowledged as the ground of the covenant relationship.</p>",
    "8": "<p><span class='term'>wattiqrōt ʿimmô habbᵉrît</span> — and you cut the covenant with him (9:8). The phrase <span class='term'>kārat bᵉrît</span> (to cut a covenant) is the standard covenant-making formula throughout the OT, derived from the ritual cutting of animals in covenant ceremonies (cf. Gen 15:9-18, where the smoking firepot passed through the cut pieces). The specific covenant content enumerated here — to give the land of the Canaanites, Hittites, Amorites, Perizzites, Jebusites, and Girgashites — quotes the Abrahamic land-grant language of Gen 15:19-21 with slight variation. <span class='term'>wattāqem ʾet-dᵉḇārêḵā kî ṣaddîq ʾāttāh</span> — and you fulfilled your words, for you are righteous — the keeping of the land promise is grounded in YHWH's <em>ṣeḏeq</em> (righteousness = covenant-faithfulness): what he commits to, he performs.</p>",
    "9": "<p><span class='term'>wattiḇrʾê ʾet-ʾᵃnî ʾăḇōtênû bᵉMiṣrāyim</span> — you saw the affliction of our ancestors in Egypt (9:9). The verb <span class='term'>rāʾāh</span> (to see) in YHWH's perception of Israel's suffering echoes Exod 3:7: <em>rāʾōh rāʾîtî ʾet-ʿonî ʿammî</em> (I have indeed seen the affliction of my people) — the burning-bush commissioning speech. The prayer quotes the Exodus theology directly: YHWH's seeing of suffering is not passive observation but the trigger of redemptive action. <span class='term'>wayyiṭṭəʿûnê ʾel-yam sûph</span> (they cried out to the Reed Sea) — the unusual construction here suggests the cry was at/toward the Reed Sea, i.e., at the moment of maximum threat, establishing the prayer's structural pattern of crisis → cry → divine response.</p>",
    "10": "<p><span class='term'>wattittēn ʾôtôt ûmôpᵉtîm bᵉPharʿōh</span> — you performed signs and wonders against Pharaoh (9:10). The dual formula <span class='term'>ʾôtôt ûmôpᵉtîm</span> (signs and wonders) is the technical compound for the Exodus plagues throughout Deuteronomy (Deut 4:34; 6:22; 7:19; 26:8) — the prayer is drawing on the Deuteronomic theological tradition. <span class='term'>ḵî yāḏaʿtā kî hēzîḏû ʿălêhem</span> — for you knew that they acted arrogantly against them — the verb <span class='term'>hēzîḏ</span> (to act with arrogant presumption) is the same root as <em>zēḏôn</em> (arrogance/presumption) — framing Pharaoh's resistance as the covenant-violation of presumptuous pride against YHWH's people and word.</p>",
    "11": "<p><span class='term'>wᵉhayyām bāqaʿtā liphᵉnêhem</span> — you split the sea before them (9:11). The verb <span class='term'>bāqaʿ</span> (to split, cleave) is the standard Reed Sea vocabulary (cf. Ps 78:13; Isa 63:12) — a violent fissuring rather than a gradual receding. The spatial metaphors that follow — <em>wayyaʿăḇᵉrû ḇᵉtôḵ hayyām bayyabbāšāh</em> (they crossed through the midst of the sea on dry ground) — combines the inside-the-sea location with the dry-ground mode: the miracle consists in both the path through and the floor condition. The destroying of their pursuers is expressed with <span class='term'>ḵᵉʾeḇen bᵉmayim ʿazzîm</span> (like a stone in mighty waters) — the simile from the Song of the Sea (Exod 15:5, 10) confirming the prayer's deliberate quotation of the Exodus liturgical tradition.</p>",
    "12": "<p><span class='term'>ûḇᵉʿammûḏ ʿānān hinnaḥaltām yômām</span> — by a pillar of cloud you led them by day (9:12). The <span class='term'>ʿammûḏ ʿānān / ʿammûḏ ʾēš</span> (pillar of cloud / pillar of fire) is the most concrete symbol of divine accompaniment in the wilderness tradition (Exod 13:21-22). The verb <span class='term'>nāḥāh</span> (to lead, guide) in the Hiphil — <em>hinnaḥaltām</em> — carries the sense of guided movement toward a destination: YHWH does not merely accompany but directs the journey. The night-fire and day-cloud pair constitutes a 24-hour presence: the covenant God is present continuously, not episodically.</p>",
    "13": "<p><span class='term'>wᵉʿal-har Sîynay yāraḏtā</span> — you came down on Mount Sinai (9:13). The descent of YHWH to Sinai — the same verb <span class='term'>yāraḏ</span> as in Exod 19:20 — establishes the theophany as a movement of divine condescension: YHWH comes down to communicate at the human level. The content summary — <em>mišpāṭîm ʾĕmet tôrôt ṭôḇôt ḥuqqîm ûmiṣwôt ṭôḇôt</em> (true judgments, good laws, good statutes and commandments) — uses three different Hebrew legal terms piled up to express the comprehensiveness and quality of the Sinai revelation. <span class='term'>ṭôḇôt</span> (good) applied twice to the legal content makes an ethical claim: the Torah is not merely authoritative but intrinsically beneficial.</p>",
    "14": "<p><span class='term'>wᵉʾet-šabbat qoḏšᵉḵā hôḏaʿtā lāhem</span> — and your holy Sabbath you made known to them (9:14). The verb <span class='term'>yāḏaʿ</span> in the Hiphil — <em>hôḏaʿtā</em> (you caused them to know, you revealed) — frames the Sabbath as revealed knowledge rather than natural intuition: Israel learned the Sabbath from YHWH, not from nature or reason. This is significant for the later Nehemiah covenant pledge (10:31) to observe the Sabbath: its observance is a response to divine disclosure, not cultural convention. <span class='term'>šabbat qoḏšᵉḵā</span> — holy Sabbath — the construct chain makes the Sabbath YHWH's property: it is holy because it belongs to him, not merely because it is designated special.</p>",
    "15": "<p><span class='term'>wᵉleḥem miššāmayim nātattāh lāhem</span> — bread from heaven you gave them (9:15). <span class='term'>leḥem miššāmayim</span> (bread from heaven) is the earliest interpretive gloss of the manna miracle, framing it as supernatural provision rather than a natural phenomenon. The same phrase appears in Ps 105:40 and is picked up by Jesus in John 6:31-35 where the manna-bread from heaven becomes the typological ground for the claim that Christ himself is the true bread from heaven. <span class='term'>wayyibbāqᵉʿû</span> (they split open the rock, v. implied water-from-rock) — the combination of manna and water from the rock as parallel wilderness provisions establishes a sustenance typology that the NT develops as baptism and Eucharist (1 Cor 10:3-4).</p>",
    "16": "<p><span class='term'>wᵉhēm ûʾăḇôtênû hēzîḏû wayyaqšû ʾet-ʿorpām</span> — but they and our ancestors acted arrogantly and stiffened their neck (9:16). The pair <span class='term'>hēzîḏ</span> (presumptuous arrogance) and <span class='term'>qāšāh ʿōreph</span> (stiff-necked; lit. to harden the neck) constitute the Pentateuch's standard description of Israel's wilderness rebellion. <em>qᵉšê ʿōreph</em> first appears at the golden calf episode (Exod 32:9; 33:3, 5; 34:9) as YHWH's characterization of the people. The imagery is from ox-training: a stiff-necked ox refuses to yield to the yoke. Applied to Israel, it describes the refusal to submit to YHWH's direction — the covenantal failure of corporate stubbornness.</p>",
    "17": "<p><span class='term'>wāyimʾᵃnû lišmōaʿ wᵉlōʾ-zāḵᵉrû nipᵉlʾōtêḵā ʾăšer ʿāśîtā ʿimmāhem</span> — they refused to listen and did not remember your wonders that you did for them (9:17). The refusal-to-hear formula (<em>māʾēn lišmōaʿ</em>) is the Prophets' primary indictment of Israel: hearing and obeying are a single act in Hebrew, so <em>šāmaʿ</em> = responsive obedience. Not listening = not obeying. The forgetting of wonders — <em>lōʾ-zāḵᵉrû nipᵉlʾōtêḵā</em> — identifies memory as a covenant obligation: Israel is covenantally required to remember the Exodus (Deut 8:2) and forgetting constitutes a breach. <span class='term'>wayyāšûḇû bᵉmirʾyāhem</span> — they appointed a leader to return to their slavery — the golden-calf demand for a leader to return to Egypt (Exod 32; Num 14:4) is the ultimate covenant-inversion: choosing slavery over freedom.</p>",
    "18": "<p><span class='term'>ʾap kî ʿāśû lāhem ʿēgel massēḵāh</span> — even when they had made themselves a cast image of a calf (9:18). The <span class='term'>massēḵāh</span> (cast/molten image) is distinguished from the <span class='term'>pesel</span> (carved/chiseled image) — the golden calf was made by smelting and casting donated jewelry (Exod 32:4). The phrase <span class='term'>wayyōʾmᵉrû zeh ʾĕlōhêḵā ʾăšer heʿĕlîtḵā miMiṣrāyim</span> — this is your God who brought you up from Egypt — quotes Exod 32:4 directly. The substitution of a manufactured object for YHWH as the subject of the Exodus is the precise definition of idolatry in the OT: attributing the covenant-redemption act to a created thing.</p>",
    "19": "<p><span class='term'>wᵉʾattāh bᵉraḥămeḵā hārabbîm lōʾ-ʿăzaḇtām bammidbar</span> — yet in your great mercies you did not abandon them in the wilderness (9:19). The <span class='term'>raḥămîm hārabbîm</span> (great mercies/compassions; plural of <em>reḥem</em>, womb) is the word for the visceral, parental compassion of YHWH — the mercy that operates like a parent unable to abandon a child (Isa 49:15). <span class='term'>lōʾ-ʿăzaḇtām</span> (you did not abandon them) is the theological spine of the prayer: this refrain appears at vv. 17, 19, and 31, creating the structural repetition of divine faithfulness against which each wave of human rebellion is measured.</p>",
    "20": "<p><span class='term'>wᵉrûaḥᵃkā haṭṭôḇāh nātattāh lᵉhaskîlām</span> — you gave your good Spirit to instruct them (9:20). <span class='term'>rûaḥ haṭṭôḇāh</span> (the good Spirit) is an unusual compound — the only OT occurrence of the Spirit explicitly qualified as <em>ṭôḇ</em> (good) in this way (Ps 143:10 has <em>rûaḥᵃkā ṭôḇāh</em> as a parallel structure). The function attributed is <em>lᵉhaskîlām</em> — to make them wise/discerning; the Hiphil of <span class='term'>śākal</span> (to be wise, successful, prudent). The Spirit's work is cognitive and directional: causing insight rather than merely accompanying. This is the OT ground for the NT's teacher-Spirit of John 14-16.</p>",
    "21": "<p><span class='term'>wᵉʾarbāʿîm šānāh killkaltām bammidbar lōʾ ḥāsērû</span> — and forty years you sustained them in the wilderness; they lacked nothing (9:21). The verb <span class='term'>kûl</span> in the Pilel — <em>killkaltām</em> — means to sustain, nourish, maintain; the intensive form expressing comprehensive provision. <span class='term'>lōʾ ḥāsērû</span> — they lacked nothing — is the total-sufficiency formula, quoting Deut 2:7 (<em>yāḏaʿ YHWH ʾĕlōhêḵā ʾet-haliḵtᵉḵā... lōʾ ḥāsartā dāḇār</em>). <span class='term'>שַׂלְמֹתֵיהֶם לֹא בָלוּ</span> (their garments did not wear out) — the clothing-miracle detail from Deut 8:4 — is cited as evidence of the comprehensive nature of divine provision: even secondary needs were met without deterioration.</p>",
    "22": "<p><span class='term'>wattittēn lāhem mamlāḵôt wᵉʿammîm</span> — you gave them kingdoms and peoples (9:22). The Conquest is summarized in terms of political-geographical transfer: YHWH gave kingdoms to Israel. <span class='term'>wattaḥᵃlqēm lᵉpēʾāh</span> — you distributed them as a boundary/portion — the <em>pēʾāh</em> (corner, boundary) metaphor for the allotment of Canaan to the tribes. The specific mention of Sihon king of Heshbon and Og king of Bashan (the two Transjordanian kings of Num 21; Deut 2–3) as the paradigm cases follows the Deuteronomic pattern: these victories are the proof-of-concept that YHWH can give the land.</p>",
    "23": "<p><span class='term'>wᵉʾet-bᵉnêhem hirbîtā kᵉkôkᵉḇê haššāmayim</span> — you multiplied their children like the stars of heaven (9:23). The <em>kᵉkôkᵉḇê haššāmayim</em> (as the stars of heaven) comparison is the Abrahamic promise-formula (Gen 15:5; 22:17; 26:4; Exod 32:13; Deut 1:10; 10:22). The prayer inserts the fulfillment of the Abrahamic number-promise at the Conquest entry-point, establishing the narrative logic: the promise given to Abraham was fulfilled through the wilderness increase and confirmed at the point of entry into the land.</p>",
    "24": "<p><span class='term'>wayyāḇōʾû haḇbānîm wayyirᵉšû ʾet-hāʾāreṣ</span> — the children entered and took possession of the land (9:24). The Conquest is expressed through the dual verb pair <span class='term'>bôʾ</span> (to enter) and <span class='term'>yāraš</span> (to take possession, dispossess). <em>yāraš</em> is the Deuteronomic technical term for the Conquest as legally authorized dispossession — the taking of what YHWH has given in fulfillment of the covenant. <span class='term'>wattaḵnaʿ liphᵉnêhem ʾet-yôšᵉḇê hāʾāreṣ</span> — you subdued before them the inhabitants of the land — the Hiphil of <span class='term'>kānaʿ</span> (to subdue, humble) is YHWH's action preceding Israel's: the land is taken because YHWH has already broken the resistance.</p>",
    "25": "<p><span class='term'>wayyilkᵉḏû ʿārîm bᵉṣûrôt ûʾădāmāh šᵉmēnāh</span> — they captured fortified cities and a fat land (9:25). The <span class='term'>ʾădāmāh šᵉmēnāh</span> (fat land) is the fertility-of-Canaan formula from Deut 8:7-9 and Num 13:27 — the land described in terms of its agrarian richness. The list that follows — cisterns, vineyards, olive orchards, fruit trees — is the Deuteronomic bounty list (Deut 6:11; Josh 24:13) applied here as historical retrospect. <span class='term'>wayyōʾkᵉlû wayyiśbᵉʿû wayyašmînû</span> — they ate and were satisfied and grew fat — the three-verb sequence of eating, satisfaction, and fattening captures the irony of prosperity as spiritual danger: the same fruitful land that proved YHWH's faithfulness became the occasion for forgetting him.</p>",
    "26": "<p><span class='term'>wayyamrû wayyimrᵉdû bāk</span> — they were rebellious and revolted against you (9:26). The two near-synonymous verbs — <span class='term'>mārāh</span> (to be contentious, rebellious) and <span class='term'>māraḏ</span> (to revolt, rebel) — are deliberately doubled to express the willfulness and totality of the rebellion. <span class='term'>wayyašlîkû ʾet-tôrātᵃkā ʾaḥᵃrê gawwām</span> — they cast your law behind their back — the idiom of <em>throwing behind the back</em> expresses contemptuous rejection: turning away from what one refuses to acknowledge. The killing of the prophets (<em>wayyahargû binhᵉʾîm</span>) is the intensification: from neglecting the law to destroying those who proclaimed it.</p>",
    "27": "<p><span class='term'>wayyiṣʿaqû ʾêlêḵā wᵉʾattāh miššāmayim tišmāʿ</span> — they cried out to you and from heaven you heard (9:27). The cry-and-hear structure is the Judges cycle compressed into its essential grammar: human distress → verbal appeal → divine hearing → deliverance. <span class='term'>wattittēn lāhem môšîʿîm</span> — you gave them saviors — the <em>môšîaʿ</em> (savior, deliverer; participle of <em>yāšaʿ</em>) is the Judges-era deliverer figure: Othniel, Ehud, Deborah, Gideon et al. as YHWH's provisional saviors. The plural <em>môšîʿîm</em> acknowledges the cyclical and multiple nature of the deliverances — no single savior sufficed, establishing the theological need for the one permanent Savior.</p>",
    "28": "<p><span class='term'>ûḵᵉnōaḥ lāhem yāšûḇû laʿăśôt raʿ lᵉpānêḵā</span> — when they had rest they returned to doing evil before you (9:28). The pattern of <span class='term'>nûaḥ</span> (rest, safety) → apostasy → oppression → cry → deliverance is the Judges cycle formula (Judg 2:11-19) stated explicitly. The verb <span class='term'>wayyaʿazᵉḇêm bᵉyaḏ ʾôyᵉḇêhem</span> (you abandoned them to the hand of their enemies) uses <em>ʿāzaḇ</em> — the same word the prayer uses elsewhere for Israel's forsaking of YHWH (v. 26) — making the abandonment reciprocal: Israel abandoned YHWH; YHWH abandoned them.</p>",
    "29": "<p><span class='term'>wattāʿaḏ bāhem lᵉhāšîḇām ʾel-tôrātᵉḵā</span> — you warned them to return to your law (9:29). The Hiphil of <span class='term'>ʿûḏ</span> (to warn, testify, admonish) designates the prophetic warning function: the prophets are YHWH's instruments of covenant admonition. <span class='term'>wᵉlōʾ-šāmᵉʿû wayyaḥᵃṭîʾû bᵉmiṣwōtêḵā</span> — they did not listen and sinned against your commandments — the not-listening formula closes the cycle. <span class='term'>ûmišpāṭîm ʾăšer-yaʿăśeh ʾôtām hāʾāḏām wāḥay bāhem</span> — the ordinances by which a person who does them shall live in them — quotes Lev 18:5, the foundational law-life equation: the Torah is life-giving; refusing it is refusing life.</p>",
    "30": "<p><span class='term'>wattimšōk ʿălêhem šānîm rabbôt</span> — you were patient with them for many years (9:30). The verb <span class='term'>māšaḵ</span> (to draw out, extend, prolong) in this context means to extend time/patience — YHWH stretched out the years before judgment, consistent with the <em>ʾerek ʾappayim</em> (long-tempered, slow to anger) character announced in Exod 34:6. <span class='term'>wattāʿaḏ bāhem bᵉrûḥᵃkā bᵉyaḏ nᵉḇîʾêḵā</span> — you warned them through your Spirit by the hand of your prophets — the Spirit-prophet connection: the prophetic word is the Spirit's instrument of covenant warning. This is the OT basis for 2 Pet 1:21 (prophecy carried along by the Spirit) and Acts 28:25 (the Holy Spirit spoke through Isaiah).</p>",
    "31": "<p><span class='term'>wᵉlōʾ-ʿăśîtām kālāh</span> — you did not make an end of them (9:31). The <span class='term'>kālāh</span> (complete destruction, annihilation) is the technical term for the covenant judgment of total extermination (cf. Jer 4:27; 5:10, 18; Ezek 11:13) — YHWH repeatedly threatened kālāh in the wilderness (Num 14:12; Exod 32:10) and withheld it. <span class='term'>kî ʾēl ḥannûn wᵉraḥûm ʾāttāh</span> — for you are a gracious and compassionate God — the Exod 34:6 attribute-list (<em>ḥannûn wᵉraḥûm ʾerek ʾappayim</em>) is the theological explanation for the withholding of kālāh. The preservation of the remnant against deserved total judgment is the OT form of the grace that the NT identifies as the cross — where YHWH made an end of sin without making an end of sinners.</p>",
    "32": "<p><span class='term'>wᵉʿattāh ʾĕlōhênû hāʾēl haggāḏôl haggibōr wᵉhannôrāʾ</span> — and now, our God, the great, mighty, and awesome God (9:32). The triple divine epithet — <span class='term'>gāḏôl, gibbōr, nôrāʾ</span> (great, mighty, awesome/fearsome) — is quoted from Deut 10:17 where Moses uses it in the context of YHWH's justice toward the poor and marginalized. The prayer appropriates a justice-attribute formula as the basis of a petition for justice: the great, mighty, awesome God who shows no partiality (Deut 10:17) is called to see the current covenant distress. <span class='term'>šômēr habbᵉrît wᵉhaḥesed</span> — who keeps covenant and steadfast love — the <em>bᵉrît-ḥesed</em> compound (covenant and covenant-love) appears in the same Deut 7:9 context of the faithful covenant-keeper.</p>",
    "33": "<p><span class='term'>wᵉʾattāh ṣaddîq ʿal kol-habbāʾ ʿālênû</span> — and you are righteous in all that has come upon us (9:33). The <span class='term'>ṣaddîq</span> (righteous) confession is a legal acknowledgment: YHWH's judgments are just. This is the same declaration Ezra makes in his prayer (Ezra 9:15: <em>YHWH ʾĕlōhê Yiśrāʾēl ṣaddîq ʾāttāh</em>), a formulaic acknowledgment of deserved judgment. The conjunction — you are righteous, we have sinned — is the covenantal logic: divine justice is affirmed before mercy is requested, establishing that any relief that follows is grace rather than entitlement.</p>",
    "34": "<p><span class='term'>wᵉʾet-tôrātᵃkā nātattāh ʾaḥᵃrê gawwām</span> — they set your law behind their backs (9:34). The throwing-behind-the-back idiom (cf. 9:26) is repeated for the entire leadership chain: kings, princes, priests, ancestors — the failure of covenant obedience was comprehensive and structural, not limited to a rebellious subset. <span class='term'>ûmiddᵉḇārîm ʾăšer hîḏ'tāh bāhem lōʾ ʾāzᵉnû</span> — and to the commandments by which you warned them they did not give ear — <em>ʾāzan</em> (to give ear, listen attentively) is the hearing-with-intent verb of the Shema tradition; withholding the ear from YHWH's words is the opposite of the covenantal listening required.</p>",
    "35": "<p><span class='term'>wᵉhēm bᵉmalḵûtām ûḇᵉṭûḇᵃkā hārāḇ ʾăšer nātattāh lāhem</span> — even in their kingdom and in your great goodness that you gave them (9:35). The ironic juxtaposition — in their kingdom, in the generous bounty you gave them — emphasizes that the apostasy came from a position of covenanted abundance. The phrase <span class='term'>lōʾ ʿăḇāḏûk wᵉlōʾ-šāḇû mimmallᵃkôtēhem</span> — they did not serve you and did not turn from their evil deeds — identifies non-service to YHWH as the root sin: the covenant relationship is fundamentally one of service (<em>ʿāḇaḏ</em>), and the refusal to serve = covenant breach.</p>",
    "36": "<p><span class='term'>hinnêh ʾănaḥnû hayyôm ʿăḇāḏîm</span> — behold, we are slaves today (9:36). The <span class='term'>ʿāḇeḏ</span> (slave, servant) self-designation in the context of the land-promise is the prayer's ultimate irony: the descendants of those freed from Egyptian slavery are now slaves in their own covenant-land. The land YHWH gave for flourishing now produces revenue for Persian overlords. The movement from <em>ʿeḇed</em> in Egypt (Exod 1) to <em>ʿeḇed</em> in Judah under Persia traces the complete Deuteronomic arc: the curses of Deut 28:68 for covenant failure include the threat of return to slavery.</p>",
    "37": "<p><span class='term'>wᵉtᵉḇûʾātāh marbāh lamlāḵîm ʾăšer nātattāh ʿālênû</span> — its rich yield goes to the kings you have set over us (9:37). The <span class='term'>tᵉḇûʾāh</span> (yield, produce; the product of the land's fruitfulness) is the Deuteronomic term for the covenant blessing of agricultural abundance (Deut 14:22; 16:15; 26:12). The irony is complete: the land's productivity — which should be the covenanted people's blessing — flows instead to Achaemenid tax collection. <span class='term'>ûḇiḡwiyyōtênû môšᵉlîm kîrṣônām</span> — they have dominion over our bodies as they please — <em>ḵiṣônām</em> (according to their will/pleasure) is the Persian administrative prerogative: the post-exilic community is at the mercy of imperial will rather than covenant promise.</p>",
    "38": "<p><span class='term'>ûḇᵉkol-zōʾt ʾănaḥnû kōrᵉtîm ʾĕmūnāh</span> — in all this we are making a firm/faithful covenant (9:38). <span class='term'>kārat ʾĕmûnāh</span> is a slightly unusual covenant formula: rather than the standard <em>kārat bᵉrît</em> (cut a covenant), <em>ʾĕmûnāh</em> (faithfulness, steadfastness, reliability) qualifies the nature of the covenant being enacted: it is a covenant of faithfulness — both a commitment to faithfulness and a covenant characterized by the quality of the divine faithful partner. The sealing (<em>ḥôtāmênû</em>, those stamping with seals) and writing (the scroll) give the covenant legal documentary form: the post-exilic community's recommitment is a notarized public covenant.</p>"
  },
  "10": {
    "1": "<p><span class='term'>hattirshātāʾ</span> — the Governor (10:1). <span class='term'>tirshātāʾ</span> is an Aramaic-Persian administrative loanword (from Old Persian <em>tarsata</em> = the feared one, the honorable one) that designates the Persian-appointed governor of a province. In Ezra-Nehemiah it is applied to Nehemiah (here and 8:9; cf. Ezra 2:63 where it designates the leader of the return). The titling of Nehemiah as <em>tirshātāʾ</em> at the head of the covenant document positions the civil authority alongside the priestly and Levitical representatives: the covenant renewal involves all social strata of the restoration community.</p>",
    "2": "<p><span class='term'>Śᵉrayāh ʿAzaryāh</span> (10:2). The priestly family list opens ch 10:2-8 — the Yah-bearing names (compounded with YHWH) dominate: Seraiah (YHWH is prince/ruler), Azariah (YHWH has helped), Jeremiah (YHWH exalts). The priestly signatory order mirrors the genealogical framework of Neh 12 and Ezra 2 — the families certified as legitimately of Aaronic descent in the return. Their signing establishes priestly co-authorization of the covenant.</p>",
    "3": "<p><span class='term'>Pashḥûr ʾAmarYāh</span> (10:3). Pashhur is one of the priestly families that recurs across Ezra-Nehemiah (Ezra 2:38; Neh 7:41; 11:12) — an ancient priestly lineage. Amariah (YHWH has spoken/said) is likewise a recurring priestly name. The signatories in this section are family heads, not individuals: each name represents a covenant commitment binding the entire priestly house.</p>",
    "4": "<p><span class='term'>Ḥattûš Šeḇanyāh</span> (10:4). Hattush appears in the list of returnees with Ezra (Ezra 8:2) — a Davidic descendant who returned with Ezra. His presence among the priests signals either a broader use of the priestly list or a distinct Hattush from the same family. Shebaniah appears multiple times in Neh 9-10 as a Levitical/priestly name.</p>",
    "5": "<p><span class='term'>Mallûk Ḥārîm</span> (10:5). Harim (dedicated/consecrated) is one of the families listed in both the priestly return inventory (Ezra 2:39; Neh 7:42) and the Ezra 10 intermarriage list (10:31) — a priestly family with a documented post-exilic history of covenant struggle and covenant renewal. The recurrence of these names across multiple lists establishes the historicity of the community's institutional memory.</p>",
    "6": "<p><span class='term'>Meremôt ʿOḇadyāh</span> (10:6). Meremoth son of Uriah the priest is attested as the official who weighed the temple vessels brought by Ezra (Ezra 8:33) — giving him a specific administrative role in the restoration. His presence on the covenant document locates his signature within a broader career of priestly-administrative service to the post-exilic community.</p>",
    "7": "<p><span class='term'>ʾAḇiyyāh Miyyāmîn</span> (10:7). Abijah (YHWH is father) is one of the 24 priestly divisions established by David (1 Chr 24:10) — the connection to the Davidic liturgical organization grounds the post-exilic priestly structure in the pre-exilic temple service. The renewal of these divisions in Neh 12:4, 17 shows continuity between the Solomonic/Davidic temple orders and the restoration community.</p>",
    "8": "<p><span class='term'>Bilgay Šemayāh — ʾēlleh haKōhănîm</span> (10:8). The priestly signatory list closes with the descriptor: these are the priests. The list of 21 priestly family heads in 10:2-8 represents the institutional hierarchy of the restoration priesthood. Their covenant commitment is simultaneously personal and corporate: each family bound itself and its descendants to the covenant terms that follow.</p>",
    "9": "<p><span class='term'>Yēšûaʿ ben-ʾAzanyāh</span> (10:9). The Levitical list opens with Joshua son of Azaniah — a different Joshua from the high priest Jeshua/Joshua of Ezra 2–3. The Levitical branch of the covenant community is represented by its own family heads, distinct from the priestly houses of 10:2-8. The separation of priestly and Levitical signatories reflects the institutional differentiation between the two service orders.</p>",
    "10": "<p><span class='term'>Šeḇanyāh Hôḏîyāh</span> (10:10). Shebaniah (YHWH has returned/restored) appears multiple times in the Nehemiah narrative — as a Levite in the Torah-reading assembly (9:4-5) and here among the Levitical covenant signatories. The recurrence of the same names across liturgical and legal contexts establishes the personnel continuity of the Levitical leadership through the reform period.</p>",
    "11": "<p><span class='term'>Mîḵāh Rēhôḇ</span> (10:11). The name Micah (who is like YHWH?) echoes the prophet and the Levite of Judges 17-18 — a name with deep resonance in Levitical identity. Rehob (wide/open place) is a name borne by several figures in OT narrative. The Levitical names in this list tend toward theological meaning: they encode covenant identity in their etymology.</p>",
    "12": "<p><span class='term'>Ḥašaḇyāh Baqqûq Šeḇanyāh</span> (10:12). Hashabiah (YHWH has considered/reckoned) is a prominent Levitical name in Chronicles and Nehemiah — Levites of this name appear in the temple-service lists (1 Chr 6:45; 9:14; Neh 11:15; 12:21, 24). Multiple Levites share the name, reflecting the family-lineage pattern of the Levitical service orders.</p>",
    "13": "<p><span class='term'>ʾēlleh halayyᵉwiyyim — rāʾšê halayyᵉwiyyim</span> (10:13). The Levitical signatory section closes with the designation: these are the Levites — heads of the Levites. The parallel structure to the priestly list's close (10:8) reflects the formal legal drafting of the covenant document: each signatory group is introduced, listed, and closed. The symmetry signals the document's deliberate construction as a legal instrument.</p>",
    "14": "<p><span class='term'>rāʾšê hāʿām</span> — heads of the people (10:14). The lay-leadership list (10:14-27) is the third category of covenant signatories: after priests and Levites, the tribal family heads. These are the civil leaders of the non-priestly community — the lay aristocracy of Jerusalem and Judah. Their covenant commitment covers the population outside the cult personnel, making the covenant inclusive of the entire community structure.</p>",
    "15": "<p><span class='term'>Bunni ʿAzgāḏ</span> (10:15). Azgad (Gad is strong) — one of the lay families listed in the Ezra 2/Nehemiah 7 return inventories (Ezra 2:12: 1,222 sons of Azgad). The large number of returnees under this family name indicates a substantial lay community. Their representative's signature on the covenant document binds a significant portion of the lay population.</p>",
    "16": "<p><span class='term'>ʾAḏônîyāh Bighwāy ʿAḏîn</span> (10:16). Adonijah (YHWH is Lord) is a theologically loaded name — shared with David's son and with a different leader in the return (Ezra 2:13). Bigvai appears in the return lists as another substantial family (Ezra 2:14: 2,056). The presence of family heads from the major returnee groups confirms that the covenant document represents the institutional leadership of the restoration community.</p>",
    "17": "<p><span class='term'>ʾĀṭēr Ḥizziqîyāh ʿAzzûr</span> (10:17). Ater (bound/closed) — a family represented in the gatekeepers of the return (Ezra 2:42: 98 gatekeepers). The laypeople's list includes service families as well as large tribal groups, showing the covenant's breadth: it encompasses the full social hierarchy from tribal leaders to temple servants.</p>",
    "18": "<p><span class='term'>Hôḏîyāh Hāšûm Bēṣay</span> (10:18). Hashum — another return-list family (Ezra 2:19: 223 men). The repetition of family names across Ezra 2, Nehemiah 7, and Nehemiah 10 creates a documentary thread: the same families who returned from Babylon under Zerubbabel are now, two generations later, sealing a covenant document. The continuity of family identity across the generations of the restoration is itself theologically significant.</p>",
    "19": "<p><span class='term'>Ḥārîph ʿAnātôt</span> (10:19). Anathoth — the hometown of Jeremiah (Jer 1:1) — is here a family name, not the town. The association of this name with the most prominent prophetic figure of the exile period may be intentional: the community signing this covenant document stands in the line of those who heard Jeremiah's call to covenant faithfulness.</p>",
    "20": "<p><span class='term'>Maggîyāš Mešullām</span> (10:20). Meshullam is one of the most common names in the return lists — multiple Meshullams appear across Ezra-Nehemiah (Ezra 8:16; 10:15, 29; Neh 3:4, 6, 30; 6:18; 8:4; 11:7, 11; 12:13, 16). The name means friend/ally — a name carried by diverse individuals from priestly, Levitical, and lay lines.</p>",
    "21": "<p><span class='term'>Mᵉšēzaḇʾēl Ṣāḏôq</span> (10:21). Meshezabel (God has delivered) — a theophoric name expressing confidence in divine redemption. Zadok is the great priestly name of Israelite history — the high priest of David's era (2 Sam 15:24-29) whose line retained the Jerusalem priesthood through the monarchy. The presence of a Zadok among the lay leaders (not in the priestly list) suggests a non-priestly bearer of the historic name.</p>",
    "22": "<p><span class='term'>Pellāṭyāh Ḥānān ʾĂnāyāh</span> (10:22). Pelaiah (YHWH is marvelous/distinguishes) — the theological naming pattern continues throughout the lay list. The consistent Yah-bearing names across the signatory list reflect the covenantal identity of the community: they bear in their very names the assertion of YHWH's redemptive activity.</p>",
    "23": "<p><span class='term'>Hôšēaʿ Ḥananyāh Ḥaššûḇ</span> (10:23). Hoshea — the name of the last king of Israel (2 Kgs 17:1-6) and also the original name of Joshua (Num 13:8) — here continues its currency as a lay family name. Hasshub (reckoning, esteem) appears among the wall-builders (Neh 3:11, 23) — a family active in the reconstruction before the covenant renewal.</p>",
    "24": "<p><span class='term'>Hallôḥēš Pilhāʾ Šôḇēq</span> (10:24). Hallohesh (the whisperer/enchanter) is an unusual name — also borne by a wall-builder (Neh 3:12). The diversity of names in the lay list — from theophoric to nature-based to occupational — reflects the sociological breadth of the covenant community's leadership.</p>",
    "25": "<p><span class='term'>Rêhûm Ḥašaḇnāh</span> (10:25). Rehum appears in multiple contexts in Ezra-Nehemiah: an opponent in Ezra 4:8-9 and a Levitical family in the return (Neh 12:3). The coincidence of names with opponents of the restoration in some cases and participants in others reflects the complex social history of the Persian-period Judean community.</p>",
    "26": "<p><span class='term'>ʾĂḥîyāh Ḥānān ʾĀnān</span> (10:26). Ahijah (YHWH is brother) — the name of the prophet who announced the division of the kingdom to Jeroboam (1 Kgs 11:29-40). Its recurrence as a lay family name in the post-exilic community keeps the prophetic tradition alive in family identity. The naming of children after prophets and judges was a form of covenant memory.</p>",
    "27": "<p><span class='term'>Mallûk Ḥārîm Baʿanāh — ʾēlleh śārê hāʿām</span> (10:27). The lay signatory list closes with: these are the princes/leaders of the people. The triple-tier structure of the covenant document — priests (10:2-8), Levites (10:9-13), lay leaders (10:14-27) — mirrors the social organization of the post-exilic community and ensures comprehensive institutional commitment to the covenant's terms.</p>",
    "28": "<p><span class='term'>wᵉkol-hannibdāl mēʿammê hāʾărāṣôt ʾel-tôrat hāʾĕlōhîm</span> — all who separated themselves from the peoples of the lands to the law of God (10:28). The <span class='term'>nip'al of bāḏal</span> (to separate oneself) here defines the community's membership criterion: those who have enacted the covenant separation of ch 9–10. The phrase extends the covenant beyond the formal signatories to include all who have made the same separation — spouses, children, gatekeepers, singers, Nethinim. <span class='term'>kol-yôḏēaʿ mēḇîn</span> — everyone who has knowledge and understanding — the covenant applies to those with capacity to understand covenant obligation, not merely by heredity.</p>",
    "29": "<p><span class='term'>ḥăzāq bᵉʾaḥêhem ʾaddîrêhem</span> — they joined their brothers, their nobles (10:29). <span class='term'>ḥāzaq bᵉ</span> (to hold firmly to, join oneself firmly to) is the verb of covenant adherence: clinging to rather than loose association. The legal formula that follows — <span class='term'>ʾālāh ûšᵉḇûʿāh</span> (curse and oath) — is the full covenant-sealing instrument: the <em>ʾālāh</em> (self-imprecation; curse if the covenant is violated) combined with the <em>šᵉḇûʿāh</em> (sworn oath). The bilateral structure invokes both divine sanction and personal obligation: breaking the covenant brings the curse; keeping it fulfills the oath.</p>",
    "30": "<p><span class='term'>lōʾ nittēn bᵉnôtênû lᵉʿammê hāʾāreṣ</span> — we will not give our daughters to the peoples of the land (10:30). The intermarriage prohibition is the first substantive covenant pledge — the lesson directly drawn from the Ezra 9-10 crisis. <span class='term'>wᵉlōʾ niqaḥ bᵉnôtêhem lᵉḇānênû</span> — and we will not take their daughters for our sons — the bilateral formulation covers both directions of intermarriage. The covenant pledge is forward-looking: the community binds itself for future generations, not merely addressing the past crisis.</p>",
    "31": "<p><span class='term'>wᵉʿammê hāʾāreṣ hamméḇîʾîm ʾet-hammiqqāḥôt wᵉḵol-šeḇer bᵉyôm haššabbāt lišbōr</span> — if the peoples of the land bring wares or any grain on the Sabbath to sell (10:31). The Sabbath-commerce covenant builds on Nehemiah's later enforcement narrative (13:15-22) — the covenant pledge precedes the enforcement crisis, or both covenant and crisis reflect the same ongoing problem. <span class='term'>niqaḥ mēhem bᵉšabbāt ûḇᵉyôm qōḏeš</span> — we will not buy from them on the Sabbath or on a holy day — the prohibition is on purchasing as well as selling: both sides of a commercial transaction violate Sabbath rest. <span class='term'>winᵉṭōš ʾet-haššānāh haššᵉḇîʿît</span> — and we will forgo the produce of the seventh year — the Sabbath-year release of Lev 25 is included alongside the weekly Sabbath: the covenant commits to the full Sabbath-framework of Israel's law.</p>",
    "32": "<p><span class='term'>wᵉheʿĕmadnû ʿālênû miṣwōt</span> — we set commandments upon ourselves (10:32). <span class='term'>heʿĕmîḏ ʿal</span> (to set upon, to impose on oneself) is an unusual reflexive construction for self-imposed obligation — the community is voluntarily taking on the temple tax. <span class='term'>šᵉlîšit haššeqel baššānāh lᵉʿăḇôḏat bêt ʾĕlōhênû</span> — a third of a shekel per year for the service of the house of our God — the Mosaic tradition prescribed a half-shekel (Exod 30:13-16) as the census tax; the reduction to a third-shekel may reflect Persian-era economic conditions or a deliberately modest community standard.</p>",
    "33": "<p><span class='term'>lᵉleḥem hammaʿăreḵet ûminḥat hattāmîḏ ûlᵉʿôlat hattāmîḏ</span> — for the showbread, the regular grain offering, and the regular burnt offering (10:33). The list of temple service categories the community funds with the annual contribution — <span class='term'>leḥem hammaʿăreḵet</span> (bread of the arrangement/Presence; showbread), the daily <em>minḥāh</em> (grain offering), and the daily <em>ʿôlāh</em> (burnt offering) — represents the regular cult operations of the Second Temple. The Sabbaths, new moons, appointed feasts, holy things, and sin offerings are all included: the community is committing to the complete liturgical funding of the restored temple service.</p>",
    "34": "<p><span class='term'>wᵉhaggôrālôt hippalnû ʿal-qurbat hāʾēṣîm</span> — we cast lots for the wood offering (10:34). The <span class='term'>qurban hāʾēṣîm</span> (wood offering, lit. drawing-near of wood) is not explicitly mentioned in the Pentateuchal law — the Temple Scroll from Qumran (11QT) and Josephus (War 2.17.6) attest a festival of wood-offering in the Second Temple period. The casting of lots (<em>gôrāl</em>) to distribute the responsibility equitably across priestly families and lay families is the covenant community's practical solution to an administrative challenge. The wood offering ensured the continuous supply of fuel for the altar fire (Lev 6:9-13).</p>",
    "35": "<p><span class='term'>ûlᵉhāḇîʾ ʾet-bikkûrê ʾadmātênû ûbikkûrê kol-pᵉrî kol-ʿēṣ</span> — to bring the firstfruits of our ground and the firstfruits of all fruit of every tree (10:35). <span class='term'>bikkûrîm</span> (firstfruits) is the Pentateuchal term for the first-and-best of the agricultural harvest dedicated to YHWH (Exod 23:19; 34:26; Num 18:12-13; Deut 26:1-11). The dedication of the firstfruits is the covenanted acknowledgment that the land and its produce belong to YHWH: the first portion represents and consecrates the whole. The Feast of Weeks (Shavuot) was the primary firstfruits festival — the community here pledges its annual observance.</p>",
    "36": "<p><span class='term'>wᵉʾet-bᵉḵôrôt bānênû ûḇhemtênû</span> — and the firstborn of our sons and our cattle (10:36). The <span class='term'>bᵉḵôr</span> (firstborn) dedication follows from the Exodus firstborn logic: YHWH claimed all firstborn human and animal at the Passover (Exod 13:2, 11-15) and the dedication/redemption of firstborn is the perpetual liturgical re-enactment of that claim. <span class='term'>kaKKātûḇ battôrāh</span> — as it is written in the law — the phrase grounds the firstborn obligation in specific Pentateuchal citation (Exod 13:2; 34:19-20; Num 18:15-16): the covenant is a return to what was already written, not new legislation.</p>",
    "37": "<p><span class='term'>wᵉʾet-rêʾšît ʿărîsōtênû wᵉterûmōtênû</span> — and the firstfruits of our dough and our contributions (10:37). <span class='term'>ʿărîsāh</span> (dough/coarse meal; the first portion of grain ground into dough) is the term in Num 15:20-21 for the dough-cake offered to YHWH from each batch: the first of the processed grain as distinct from the unprocessed firstfruits of the field. <span class='term'>terûmāh</span> (contribution, wave-offering; the portion lifted/set apart for YHWH) is the technical term for the dedicated portion of diverse goods — grain, oil, wine — set aside for the priests (Num 18:8-12). The layered agricultural vocabulary in 10:35-37 covers every stage of agricultural production from field to processed food.</p>",
    "38": "<p><span class='term'>wᵉhakkōhēn ben-ʾAhărōn yihyeh ʿim halayyᵉwiyyim bᵉʿaśēr halayyᵉwiyyim</span> — a priest of the sons of Aaron shall be with the Levites when the Levites receive the tithe (10:38). The priestly oversight of the Levitical tithe collection is grounded in Num 18:26-28: the Levites tithe their tithe to the priests. The covenant pledge specifies the accompanying priest to ensure accountability — a detail that reflects the administrative realities of post-exilic temple finance. <span class='term'>wᵉhalayyᵉwiyyim yaʿălû ʾet-maʿaśar hammaʿăśēr lᵉḇêt ʾĕlōhênû</span> — the Levites bring the tithe of the tithe to the house of our God — the double-tithe system maintained the temple treasury's share even as the primary tithe went to the Levites.</p>",
    "39": "<p><span class='term'>lōʾ naʿăzōḇ ʾet-bêt ʾĕlōhênû</span> — we will not neglect the house of our God (10:39). The covenant climax is expressed in a single negative commitment: <span class='term'>lōʾ naʿăzōḇ</span> (we will not forsake/neglect). <span class='term'>ʿāzaḇ</span> (to forsake, leave, abandon) is the most theologically loaded verb in the covenant vocabulary: it is what Israel repeatedly did to YHWH (9:26: <em>wayyaʿazᵉḇûk</em>) and what YHWH refused to do to Israel (9:31: <em>lōʾ-ʿăzaḇtām</em>). The community's final pledge mirrors YHWH's own covenant faithfulness: as YHWH refused to forsake them, so they commit not to forsake his house. The covenant document ends where it began — in the vocabulary of the divine-human abandonment/faithfulness dialectic that ran through the entire Levitical prayer.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'nehemiah')
    merge_comm(c, DATA)
    save_comm('mkt-original', 'nehemiah', c)
    count = sum(len(v) for v in DATA.values())
    print(f'nehemiah mkt-original: wrote {count} verses across ch 9-10')

if __name__ == '__main__':
    main()
